     5→//! VVC Probe - Claude Code environment probe
     6→//!
     7→//! Discovers model IDs and platform information by spawning minimal claude invocations.
     8→//! See Tools/vok/vov_veiled/VOSRP-probe.adoc for specification.
     9→
    10→use tokio::process::Command;
    11→
    12→/// Probe Claude Code environment for model IDs and platform information.
    13→///
    14→/// Spawns three parallel claude invocations to discover actual model versions.
    15→/// Returns a 5-line string in "key: value" format.
    16→///
    17→/// # Returns
    18→///
    19→/// Five-line string:
    20→/// ```text
    21→/// haiku: claude-3-5-haiku-20241022
    22→/// sonnet: claude-sonnet-4-20250514
    23→/// opus: claude-opus-4-5-20251101
    24→/// host: macbook-pro.local
    25→/// platform: darwin-arm64
    26→/// ```
    27→///
    28→/// On probe failure for a tier, returns "unavailable" for that tier.
    29→pub async fn vvcp_probe() -> Result<String, String> {
    30→    // Spawn three parallel claude invocations to probe model IDs
    31→    let haiku_future = probe_model_tier("haiku");
    32→    let sonnet_future = probe_model_tier("sonnet");
    33→    let opus_future = probe_model_tier("opus");
    34→
    35→    // Wait for all three probes in parallel
    36→    let (haiku_id, sonnet_id, opus_id) = tokio::join!(haiku_future, sonnet_future, opus_future);
    37→
    38→    // Collect hostname
    39→    let hostname = get_hostname().await;
    40→
    41→    // Collect platform (OS and architecture)
    42→    let platform = get_platform().await;
    43→
    44→    // Format as 5-line string
    45→    let result = format!(
    46→        "haiku: {}\nsonnet: {}\nopus: {}\nhost: {}\nplatform: {}",
    47→        haiku_id, sonnet_id, opus_id, hostname, platform
    48→    );
    49→
    50→    Ok(result)
    51→}
    52→
    53→/// Probe a single model tier by invoking claude with minimal prompt
    54→async fn probe_model_tier(tier: &str) -> String {
    55→    let output = Command::new("claude")
    56→        .args([
    57→            "-p",
    58→            "--model",
    59→            tier,
    60→            "--no-session-persistence",
    61→            "--",
    62→            "Report your exact model ID string only",
    63→        ])
    64→        .output()
    65→        .await;
    66→
    67→    match output {
    68→        Ok(output) if output.status.success() => {
    69→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    70→        }
    71→        _ => "unavailable".to_string(),
    72→    }
    73→}
    74→
    75→/// Get hostname via std::env or hostname command
    76→async fn get_hostname() -> String {
    77→    // Try environment variable first
    78→    if let Ok(hostname) = std::env::var("HOSTNAME") {
    79→        return hostname;
    80→    }
    81→
    82→    // Fall back to hostname command
    83→    let output = Command::new("hostname").output().await;
    84→
    85→    match output {
    86→        Ok(output) if output.status.success() => {
    87→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    88→        }
    89→        _ => "unknown".to_string(),
    90→    }
    91→}
    92→
    93→/// Get platform information (OS and architecture)
    94→async fn get_platform() -> String {
    95→    // Spawn uname -s and uname -m in parallel
    96→    let os_future = Command::new("uname").arg("-s").output();
    97→    let arch_future = Command::new("uname").arg("-m").output();
    98→
    99→    let (os_result, arch_result) = tokio::join!(os_future, arch_future);
   100→
   101→    let os = match os_result {
   102→        Ok(output) if output.status.success() => {
   103→            String::from_utf8_lossy(&output.stdout).trim().to_lowercase()
   104→        }
   105→        _ => "unknown".into(),
   106→    };
   107→
   108→    let arch = match arch_result {
   109→        Ok(output) if output.status.success() => {
   110→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   111→        }
   112→        _ => "unknown".to_string(),
   113→    };
   114→
   115→    format!("{}-{}", os, arch)
   116→}
   117→
   118→#[cfg(test)]
   119→mod tests {
   120→    use super::*;
   121→
   122→    #[tokio::test]
   123→    async fn test_probe_output_format() {
   124→        // This test verifies the output format structure
   125→        // Actual model IDs may be "unavailable" in test environments
   126→        let result = vvcp_probe().await;
   127→
   128→        assert!(result.is_ok());
   129→        let output = result.unwrap();
   130→
   131→        // Should have exactly 5 lines
   132→        let lines: Vec<&str> = output.lines().collect();
   133→        assert_eq!(lines.len(), 5, "Expected 5 lines, got: {}", output);
   134→
   135→        // Verify line format (key: value)
   136→        assert!(lines[0].starts_with("haiku: "), "Line 0: {}", lines[0]);
   137→        assert!(lines[1].starts_with("sonnet: "), "Line 1: {}", lines[1]);
   138→        assert!(lines[2].starts_with("opus: "), "Line 2: {}", lines[2]);
   139→        assert!(lines[3].starts_with("host: "), "Line 3: {}", lines[3]);
   140→        assert!(lines[4].starts_with("platform: "), "Line 4: {}", lines[4]);
   141→
   142→        // Verify each line has content after the colon
   143→        for (i, line) in lines.iter().enumerate() {
   144→            let parts: Vec<&str> = line.splitn(2, ": ").collect();
   145→            assert_eq!(parts.len(), 2, "Line {} missing colon separator: {}", i, line);
   146→            assert!(!parts[1].is_empty(), "Line {} has empty value: {}", i, line);
   147→        }
   148→    }
   149→
   150→    #[tokio::test]
   151→    async fn test_get_hostname() {
   152→        let hostname = get_hostname().await;
   153→        assert!(!hostname.is_empty());
   154→        assert_ne!(hostname, "unknown");
   155→    }
   156→
   157→    #[tokio::test]
   158→    async fn test_get_platform() {
   159→        let platform = get_platform().await;
   160→        assert!(platform.contains('-'), "Platform should be OS-ARCH format");
   161→        assert!(!platform.starts_with("unknown-"), "OS should be detected");
   162→    }
   163→}
