     5→//! Branded commit message formatting infrastructure
     6→//!
     7→//! Provides shared hallmark retrieval and message formatting for all branded commits
     8→//! (jjb: for Job Jockey, vvb: for VOK builds, etc.)
     9→
    10→use std::fs;
    11→use std::process::Command;
    12→
    13→/// Path to brand file containing vvbh_hallmark
    14→pub const VVCC_BRAND_FILE_PATH: &str = ".vvk/vvbf_brand.json";
    15→
    16→/// Path to registry file for fallback hallmark lookup
    17→pub const VVCC_REGISTRY_PATH: &str = "Tools/vok/vov_veiled/vovr_registry.json";
    18→
    19→/// JSON field name for hallmark in brand file
    20→pub const VVCC_HALLMARK_FIELD: &str = "vvbh_hallmark";
    21→
    22→/// Get hallmark for commit message versioning
    23→///
    24→/// Source logic:
    25→/// 1. Try `.vvk/vvbf_brand.json` → if exists, use `vvbh_hallmark` (4 digits)
    26→/// 2. If missing (Kit Forge) → read `Tools/vok/vov_veiled/vovr_registry.json`,
    27→///    find max hallmark, get `git rev-parse --short HEAD`, format as `{hallmark}-{commit}`
    28→pub fn vvcc_get_hallmark() -> String {
    29→    // Try reading brand file
    30→    if let Ok(brand_content) = fs::read_to_string(VVCC_BRAND_FILE_PATH) {
    31→        if let Ok(brand_json) = serde_json::from_str::<serde_json::Value>(&brand_content) {
    32→            if let Some(hallmark) = brand_json.get(VVCC_HALLMARK_FIELD) {
    33→                if let Some(hallmark_str) = hallmark.as_str() {
    34→                    return hallmark_str.to_string();
    35→                }
    36→            }
    37→        }
    38→    }
    39→
    40→    // Fallback: Kit Forge mode (read registry + git HEAD)
    41→    let mut max_hallmark = 0u32;
    42→    if let Ok(registry_content) = fs::read_to_string(VVCC_REGISTRY_PATH) {
    43→        if let Ok(registry_json) = serde_json::from_str::<serde_json::Value>(&registry_content) {
    44→            if let Some(hallmarks) = registry_json.get("hallmarks").and_then(|v| v.as_object()) {
    45→                for key in hallmarks.keys() {
    46→                    if let Ok(num) = key.parse::<u32>() {
    47→                        max_hallmark = max_hallmark.max(num);
    48→                    }
    49→                }
    50→            }
    51→        }
    52→    }
    53→
    54→    // Get short commit hash
    55→    let git_output = Command::new("git")
    56→        .args(["rev-parse", "--short", "HEAD"])
    57→        .output();
    58→
    59→    let commit_hash = if let Ok(output) = git_output {
    60→        if output.status.success() {
    61→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    62→        } else {
    63→            "0000000".to_string()
    64→        }
    65→    } else {
    66→        "0000000".to_string()
    67→    };
    68→
    69→    format!("{:04}-{}", max_hallmark, commit_hash)
    70→}
    71→
    72→/// Format a branded commit message
    73→///
    74→/// Produces: `{brand}:{hallmark}:{identity}:{action}: {subject}`
    75→/// with optional `\n\n{body}` appended.
    76→///
    77→/// Arguments:
    78→/// - brand: Commit prefix (e.g., "jjb", "vvb")
    79→/// - hallmark: Version identifier (e.g., "1011", "1011-a8c3738f")
    80→/// - identity: Context identifier (e.g., "₢AWAAb", "₣AW", "" for none)
    81→/// - action: Single-letter action code (e.g., "n", "B", "W")
    82→/// - subject: Commit subject line
    83→/// - body: Optional extended description
    84→///
    85→/// Format guarantees:
    86→/// - Four colon-delimited fields always present
    87→/// - Empty identity produces "brand:hallmark::action: subject"
    88→/// - Body separated by double newline if present
    89→/// - No trailing newlines when body is None
    90→pub fn vvcc_format_branded(
    91→    brand: &str,
    92→    hallmark: &str,
    93→    identity: &str,
    94→    action: &str,
    95→    subject: &str,
    96→    body: Option<&str>,
    97→) -> String {
    98→    let mut message = format!("{}:{}:{}:{}: {}", brand, hallmark, identity, action, subject);
    99→
   100→    if let Some(body_text) = body {
   101→        message.push_str("\n\n");
   102→        message.push_str(body_text);
   103→    }
   104→
   105→    message
   106→}
