     5→//! VVC Commit - Core commit infrastructure
     6→//!
     7→//! Provides atomic commit workflow: lock, stage, guard, commit.
     8→//! Used by vvx commit and JJK commands for consistent commit handling.
     9→//!
    10→//! ## Usage Patterns
    11→//!
    12→//! ### Simple commit (lock acquired and released automatically):
    13→//! ```ignore
    14→//! let exit_code = vvc::commit(&args);
    15→//! ```
    16→//!
    17→//! ### Protected operation (hold lock across multiple steps):
    18→//! ```ignore
    19→//! let lock = vvc::vvcc_CommitLock::vvcc_acquire()?;
    20→//! // ... do work while holding lock ...
    21→//! let hash = lock.vvcc_commit(&args)?;
    22→//! // lock released when dropped
    23→//! ```
    24→//!
    25→//! Exit codes:
    26→//!   0 - Success (commit hash printed to stdout)
    27→//!   1 - Failure (lock held, guard failed, claude failed, commit failed)
    28→
    29→use std::process::Command;
    30→
    31→use crate::vvcg_guard;
    32→
    33→/// Lock reference path for commit operations
    34→const VVCC_LOCK_REF: &str = "refs/vvg/locks/vvx";
    35→
    36→/// Arguments for commit operation
    37→///
    38→/// Note: No Default impl - callers must explicitly specify all fields,
    39→/// including size limits. Use VVCG_SIZE_LIMIT/VVCG_WARN_LIMIT constants
    40→/// for standard behavior.
    41→#[derive(Debug, Clone)]
    42→pub struct vvcc_CommitArgs {
    43→    /// Prefix string to prepend to commit message (e.g., "[jj:BRAND][F00/silks]")
    44→    pub prefix: Option<String>,
    45→    /// Commit message; if absent, invoke claude to generate from diff
    46→    pub message: Option<String>,
    47→    /// Allow empty commits (for chalk markers)
    48→    pub allow_empty: bool,
    49→    /// Skip 'git add -A' (respect pre-staged files)
    50→    pub no_stage: bool,
    51→    /// Size limit in bytes (use VVCG_SIZE_LIMIT for standard behavior)
    52→    pub size_limit: u64,
    53→    /// Warning threshold in bytes (use VVCG_WARN_LIMIT for standard behavior)
    54→    pub warn_limit: u64,
    55→}
    56→
    57→/// RAII guard that holds the commit lock.
    58→///
    59→/// The lock is automatically released when the guard is dropped, ensuring
    60→/// no code path can leak the lock. Use this when you need to hold the lock
    61→/// across multiple operations (e.g., modify gallops, then commit).
    62→///
    63→/// ## Example
    64→/// ```ignore
    65→/// let lock = vvcc_CommitLock::vvcc_acquire()?;
    66→/// // Do protected work here...
    67→/// let hash = lock.vvcc_commit(&args)?;
    68→/// // Lock released when `lock` goes out of scope
    69→/// ```
    70→pub struct vvcc_CommitLock {
    71→    /// Private field prevents external construction
    72→    _private: (),
    73→}
    74→
    75→impl vvcc_CommitLock {
    76→    /// Acquire the commit lock.
    77→    ///
    78→    /// Returns `Err` if the lock is already held by another operation.
    79→    /// The lock is held until this `vvcc_CommitLock` is dropped.
    80→    pub fn vvcc_acquire() -> Result<Self, String> {
    81→        zvvcc_acquire_lock()?;
    82→        Ok(vvcc_CommitLock { _private: () })
    83→    }
    84→
    85→    /// Perform a commit while holding the lock.
    86→    ///
    87→    /// This does NOT release the lock - the caller retains the guard
    88→    /// and can perform additional operations if needed.
    89→    ///
    90→    /// Returns the commit hash on success.
    91→    pub fn vvcc_commit(&self, args: &vvcc_CommitArgs) -> Result<String, String> {
    92→        zvvcc_run_commit_workflow(args)
    93→    }
    94→}
    95→
    96→impl Drop for vvcc_CommitLock {
    97→    fn drop(&mut self) {
    98→        zvvcc_release_lock();
    99→    }
   100→}
   101→
   102→/// Acquire the commit lock using git update-ref
   103→fn zvvcc_acquire_lock() -> Result<(), String> {
   104→    let head_output = Command::new("git")
   105→        .args(["rev-parse", "HEAD"])
   106→        .output()
   107→        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
   108→
   109→    let lock_value = if head_output.status.success() {
   110→        String::from_utf8_lossy(&head_output.stdout).trim().to_string()
   111→    } else {
   112→        "0000000000000000000000000000000000000000".to_string()
   113→    };
   114→
   115→    let result = Command::new("git")
   116→        .args(["update-ref", VVCC_LOCK_REF, &lock_value, ""])
   117→        .output()
   118→        .map_err(|e| format!("Failed to run git update-ref: {}", e))?;
   119→
   120→    if result.status.success() {
   121→        Ok(())
   122→    } else {
   123→        Err("Another commit in progress - lock held".to_string())
   124→    }
   125→}
   126→
   127→/// Release the commit lock
   128→fn zvvcc_release_lock() {
   129→    let _ = Command::new("git")
   130→        .args(["update-ref", "-d", VVCC_LOCK_REF])
   131→        .output();
   132→}
   133→
   134→/// Stage all changes including untracked files with 'git add -A'
   135→fn zvvcc_stage_changes() -> Result<(), String> {
   136→    let result = Command::new("git")
   137→        .args(["add", "-A"])
   138→        .output()
   139→        .map_err(|e| format!("Failed to run git add: {}", e))?;
   140→
   141→    if result.status.success() {
   142→        Ok(())
   143→    } else {
   144→        Err(format!(
   145→            "git add -A failed: {}",
   146→            String::from_utf8_lossy(&result.stderr)
   147→        ))
   148→    }
   149→}
   150→
   151→/// Check if there are staged changes
   152→fn zvvcc_has_staged_changes() -> Result<bool, String> {
   153→    let result = Command::new("git")
   154→        .args(["diff", "--cached", "--quiet"])
   155→        .output()
   156→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   157→
   158→    Ok(!result.status.success())
   159→}
