   161→/// Run size guard check on staged content
   162→fn zvvcc_run_guard(args: &vvcc_CommitArgs) -> Result<(), String> {
   163→    let guard_args = vvcg_guard::vvcg_GuardArgs {
   164→        limit: args.size_limit,
   165→        warn: args.warn_limit,
   166→    };
   167→
   168→    let result = vvcg_guard::vvcg_run(&guard_args, None);
   169→
   170→    match result {
   171→        0 => Ok(()),
   172→        1 => Err("Staged content exceeds size limit".to_string()),
   173→        2 => {
   174→            eprintln!("commit: WARNING - staged content near size limit");
   175→            Ok(())
   176→        }
   177→        _ => Err(format!("Guard returned unexpected code: {}", result)),
   178→    }
