   181→/// Get the staged diff for commit message generation
   182→fn zvvcc_get_staged_diff() -> Result<String, String> {
   183→    let output = Command::new("git")
   184→        .args(["diff", "--cached"])
   185→        .output()
   186→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   187→
   188→    if !output.status.success() {
   189→        return Err("git diff --cached failed".to_string());
   190→    }
   191→
   192→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   193→}
   194→
   195→/// Generate commit message using claude CLI
   196→fn zvvcc_generate_message_with_claude(diff: &str) -> Result<String, String> {
   197→    let prompt = format!(
   198→        "Generate a concise commit message for this diff:\n\n<diff>\n{}\n</diff>\n\nRespond with only the commit message, no explanation.",
   199→        diff
   200→    );
   201→
   202→    let output = Command::new("claude")
   203→        .args([
   204→            "--print",
   205→            "--system-prompt",
   206→            "Output only a conventional git commit message. No explanation or commentary. Do not wrap in markdown code blocks.",
   207→            "--model",
   208→            "haiku",
   209→            "--no-session-persistence",
   210→            &prompt,
   211→        ])
   212→        .output()
   213→        .map_err(|e| format!("Failed to invoke claude: {}", e))?;
   214→
   215→    if !output.status.success() {
   216→        let stderr = String::from_utf8_lossy(&output.stderr);
   217→        return Err(format!("claude --print failed: {}", stderr));
   218→    }
   219→
   220→    let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
   221→
   222→    // Strip markdown code blocks if Claude wrapped the response
   223→    let message = if message.starts_with("```") {
   224→        let after_opening = message.find('\n').map(|i| i + 1).unwrap_or(0);
   225→        let before_closing = message.rfind("```").unwrap_or(message.len());
   226→        if before_closing > after_opening {
   227→            message[after_opening..before_closing].trim().to_string()
   228→        } else {
   229→            message
   230→        }
   231→    } else {
   232→        message
   233→    };
   234→
   235→    // Strip Co-Authored-By trailer if Claude CLI added it from global settings
   236→    let message: String = message
   237→        .lines()
   238→        .filter(|line| !line.starts_with("Co-Authored-By:"))
   239→        .collect::<Vec<_>>()
   240→        .join("\n")
   241→        .trim()
   242→        .to_string();
   243→
   244→    if message.is_empty() {
   245→        return Err("claude returned empty message".to_string());
   246→    }
   247→
   248→    Ok(message)
   249→}
