   252→fn zvvcc_format_commit_message(prefix: Option<&str>, message: &str) -> String {
   253→    let mut full_message = String::new();
   254→
   255→    if let Some(p) = prefix {
   256→        full_message.push_str(p);
   257→    }
   258→
   259→    full_message.push_str(message);
   260→
   261→    full_message
   262→}
