   264→/// Execute the git commit
   265→fn zvvcc_execute_commit(message: &str, allow_empty: bool) -> Result<String, String> {
   266→    let mut args = vec!["commit", "-m", message];
   267→
   268→    if allow_empty {
   269→        args.push("--allow-empty");
   270→    }
   271→
   272→    let output = Command::new("git")
   273→        .args(&args)
   274→        .output()
   275→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
   276→
   277→    if !output.status.success() {
   278→        let stderr = String::from_utf8_lossy(&output.stderr);
   279→        return Err(format!("git commit failed: {}", stderr));
   280→    }
   281→
   282→    let hash_output = Command::new("git")
   283→        .args(["rev-parse", "HEAD"])
   284→        .output()
   285→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
   286→
   287→    if !hash_output.status.success() {
   288→        return Err("Failed to retrieve commit hash".to_string());
   289→    }
   290→
   291→    Ok(String::from_utf8_lossy(&hash_output.stdout)
   292→        .trim()
   293→        .to_string())
   294→}
