   296→/// Run the commit workflow.
   297→///
   298→/// Returns exit code: 0 for success, 1 for failure.
   299→/// On success, prints commit hash to stdout.
   300→///
   301→/// This is the simple API that acquires and releases the lock automatically.
   302→/// For operations that need to hold the lock across multiple steps, use
   303→/// `vvcc_CommitLock::vvcc_acquire()` instead.
   304→pub fn vvcc_run(args: &vvcc_CommitArgs) -> i32 {
   305→    let lock = match vvcc_CommitLock::vvcc_acquire() {
   306→        Ok(l) => l,
   307→        Err(e) => {
   308→            eprintln!("commit: error: {}", e);
   309→            return 1;
   310→        }
   311→    };
   312→
